#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
int n,q,a[N],s[N];
int main(){
	scanf("%d%d",&n,&q);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		s[i]=a[i]+s[i-1];
	}
	while(q--){
		int l,r,k;
		scanf("%d%d%d",&l,&r,&k);
		if(k>=r-l+1)
			printf("-1\n");
		else
			printf("%d\n",(s[r]-s[l-1]==r-l+1 && k==r-l?0:abs(k-(s[r]-s[l-1]))));
	}
	return 0;
}
